void solve(int CASE)
{
	int n; cin >> n;
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	int totw = 0;
	fa(i, 1, n)totw += g[i].size();

	var ans = vector<int>();        // 重心
	var siz = vector<int>(n + 1);   // i 子树大小
	var mxsiz = vector<int>(n + 1); // i 的每个子树大小的最大值

	var dfs = [&](var dfs, int now, int fa)->void {
		siz[now] = g[now].size(); mxsiz[now] = 0;

		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
			siz[now] += siz[to];                   // 计算 now 作为子树的大小
			mxsiz[now] = max(mxsiz[now], siz[to]); // 找 now 的每个子树大小的最大值
		}

		// 所有子树，包括父节点的
		mxsiz[now] = max(mxsiz[now], totw - siz[now]);

		if (mxsiz[now] <= totw / 2)ans.pb(now);
		};
	dfs(dfs, 1, 0);

	cout << ans.size() << endl;
	sort(all(ans));
	cout << ans << endl;
	return;
}
